// =============================================================
// SSRF Check — block private IPs before HTTP Request
// =============================================================

const item = $input.first().json;
const { resolvedConfig } = item;
const url = resolvedConfig.url;

if (!url) {
  return {
    json: {
      stepResult: { success: false, error: 'Webhook step missing url in config' },
    }
  };
}

try {
  const parsed = new URL(url);
  const hostname = parsed.hostname.toLowerCase();

  const privatePatterns = [
    /^10\./,
    /^172\.(1[6-9]|2\d|3[01])\./,
    /^192\.168\./,
    /^127\./,
    /^localhost$/i,
    /^::1$/,
    /\.local$/,
    /^0\.0\.0\.0$/,
    /^169\.254\./,
  ];

  const isPrivate = privatePatterns.some(p => p.test(hostname));
  if (isPrivate) {
    return {
      json: {
        stepResult: { success: false, error: `Webhook URL targets private address: ${hostname}` },
      }
    };
  }

  return {
    json: {
      ...item,
      webhookUrl: url,
      webhookMethod: resolvedConfig.method || 'POST',
      webhookBody: resolvedConfig.body || '{}',
      ssrfPassed: true,
    }
  };
} catch (e) {
  return {
    json: {
      stepResult: { success: false, error: `Invalid webhook URL: ${url}` },
    }
  };
}

// Build success result from HTTP response
try {
  const httpResult = $('HTTP Request').first().json;
  return {
    json: {
      stepResult: {
        success: true,
        outputPayload: {
          statusCode: httpResult.statusCode || 200,
          responseBody: typeof httpResult === 'string' ? httpResult : JSON.stringify(httpResult),
        },
      },
    }
  };
} catch (e) {
  return {
    json: {
      stepResult: { success: false, error: `Webhook failed: ${e.message}` },
    }
  };
}

// Pass through SSRF/error result
const item = $input.first().json;
return {
  json: {
    stepResult: item.stepResult,
  }
};
